# Setup Ollama para Trading Bot# Executa instalação e configuração do Ollama + Mistral$ErrorActionPreference = "Stop"Write-Host ""Write-Host "=== SETUP OLLAMA PARA TRADING BOT ===" -ForegroundColor CyanWrite-Host "Este script vai configurar a IA local (Ollama + Mistral 7B)" -ForegroundColor YellowWrite-Host ""# Verificar se Ollama está instaladofunction Test-OllamaInstalled {    try {        $null = Get-Command ollama -ErrorAction Stop        return $true    } catch {        return $false    }}# Passo 1: Verificar instalaçãoWrite-Host "[1/5] Verificando instalação do Ollama..." -ForegroundColor Cyanif (Test-OllamaInstalled) {    Write-Host "OK Ollama já está instalado!" -ForegroundColor Green    ollama --version} else {    Write-Host "ERRO Ollama não encontrado" -ForegroundColor Yellow    Write-Host ""    Write-Host "Por favor, instale o Ollama manualmente:" -ForegroundColor Yellow    Write-Host "1. Abra: https://ollama.com/download/windows" -ForegroundColor White    Write-Host "2. Baixe e execute OllamaSetup.exe" -ForegroundColor White    Write-Host "3. Após instalar, execute este script novamente" -ForegroundColor White    Write-Host ""        # Tentar abrir o navegador    Start-Process "https://ollama.com/download/windows"        Write-Host "Pressione Enter depois de instalar o Ollama..." -ForegroundColor Yellow    Read-Host        # Verificar novamente    if (-not (Test-OllamaInstalled)) {        Write-Host "ERRO Ollama ainda não foi detectado. Reinicie o terminal e tente novamente." -ForegroundColor Red        exit 1    }}# Passo 2: Verificar se o servidor está rodandoWrite-Host ""Write-Host "[2/5] Verificando servidor Ollama..." -ForegroundColor Cyan$serverRunning = $falsetry {    $response = Invoke-WebRequest -Uri "http://localhost:11434" -Method GET -TimeoutSec 2 -ErrorAction Stop    Write-Host "OK Servidor Ollama já está rodando!" -ForegroundColor Green    $serverRunning = $true} catch {    Write-Host "Servidor não está rodando. Iniciando..." -ForegroundColor Yellow        # Iniciar Ollama em background    Start-Process -FilePath "ollama" -ArgumentList "serve" -WindowStyle Hidden        Write-Host "Aguardando 5 segundos para o servidor iniciar..." -ForegroundColor Gray    Start-Sleep -Seconds 5        # Verificar novamente    try {        $response = Invoke-WebRequest -Uri "http://localhost:11434" -Method GET -TimeoutSec 2 -ErrorAction Stop        Write-Host "OK Servidor Ollama iniciado com sucesso!" -ForegroundColor Green        $serverRunning = $true    } catch {        Write-Host "ERRO Falha ao iniciar servidor. Execute manualmente: ollama serve" -ForegroundColor Red        exit 1    }}# Passo 3: Verificar modelos instaladosWrite-Host ""Write-Host "[3/5] Verificando modelos instalados..." -ForegroundColor Cyan$models = ollama list 2>&1 | Out-Stringif ($models -match "mistral") {    Write-Host "OK Modelo Mistral já está instalado!" -ForegroundColor Green} else {    Write-Host "Modelo Mistral não encontrado" -ForegroundColor Yellow    Write-Host ""    Write-Host "[4/5] Baixando modelo Mistral 7B (~4.7GB)..." -ForegroundColor Cyan    Write-Host "Isso pode levar alguns minutos dependendo da sua conexão..." -ForegroundColor Gray        ollama pull mistral        if ($LASTEXITCODE -eq 0) {        Write-Host "OK Modelo Mistral baixado com sucesso!" -ForegroundColor Green    } else {        Write-Host "ERRO ao baixar modelo. Verifique sua conexão." -ForegroundColor Red        exit 1    }}# Passo 4: Testar o modeloWrite-Host ""Write-Host "[5/5] Testando integração..." -ForegroundColor CyanWrite-Host "Enviando prompt de teste..." -ForegroundColor Gray$testResult = ollama run mistral "Responda apenas OK" 2>&1 | Out-Stringif ($testResult.Length -gt 0) {    Write-Host "OK Ollama está funcionando corretamente!" -ForegroundColor Green} else {    Write-Host "Resposta inesperada, mas servidor está ativo" -ForegroundColor Yellow}# Resumo finalWrite-Host ""Write-Host "=== CONFIGURACAO COMPLETA ===" -ForegroundColor GreenWrite-Host "OK Ollama: Instalado e rodando" -ForegroundColor GreenWrite-Host "OK Modelo: Mistral 7B disponível" -ForegroundColor GreenWrite-Host "OK API: http://localhost:11434" -ForegroundColor GreenWrite-Host ""Write-Host "Próximos passos:" -ForegroundColor CyanWrite-Host "1. Inicie o backend: python backend/server.py" -ForegroundColor WhiteWrite-Host "2. Inicie o frontend: npm start (na pasta frontend)" -ForegroundColor WhiteWrite-Host "3. Acesse o dashboard e veja as decisões da IA!" -ForegroundColor WhiteWrite-Host ""Write-Host "Comandos úteis:" -ForegroundColor CyanWrite-Host "- Ver modelos: ollama list" -ForegroundColor GrayWrite-Host "- Testar IA: ollama run mistral" -ForegroundColor GrayWrite-Host "- Parar servidor: Feche o processo ollama.exe" -ForegroundColor GrayWrite-Host ""Write-Host "Pressione Enter para continuar..." -ForegroundColor YellowRead-Host
